24 |     int LGraph::EdgesCount() const {
25 |         // 返回当前图中存在的边数（无向图中每条边算一次）
26 |         // 遍历所有邻接表，统计边数时避免重复计数
27 |         // 方法：对每条边只计 from_id < to_id 的方向（无向图）
28 |         int count = 0;
29 |         for (const auto &from_pair : adj_) {
30 |             const std::string &from_id = from_pair.first;
31 |             for (const auto &to_pair : from_pair.second) {
32 |                 const std::string &to_id = to_pair.first;
33 |                 if (directed_) {
34 |                     // 有向图：每条边都计数
35 |                     ++count;
36 |                 } else {
37 |                     // 无向图：只计 from_id < to_id 的边，避免重复
38 |                     if (from_id < to_id) {
39 |                         ++count;
40 |                     }
41 |                 }
42 |             }
43 |         }
44 |         return count;
45 |     }
