52 |     bool LGraph::exist_edge(const std::string &from_id, const std::string &to_id) const {
53 |         // 判断 from_id 与 to_id 之间是否存在边
54 |         // 先在 adj_ 中找 from_id 的邻接表，再在其中找 to_id
55 |         auto from_it = adj_.find(from_id);
56 |         if (from_it == adj_.end()) return false;
57 | 
58 |         auto to_it = from_it->second.find(to_id);
59 |         return to_it != from_it->second.end();
60 |     }
