62 |     // ==================== 顶点操作 ====================
63 | 
64 |     void LGraph::InsertVertex(const LocationInfo &vertex_info) {
65 |         // 插入顶点
66 |         //   - 若 place_id 已存在，抛出 GraphException
67 |         const std::string &id = vertex_info.place_id;
68 |         if (vertices_.find(id) != vertices_.end()) {
69 |             throw GraphException("place_already_exists: " + id);
70 |         }
71 | 
72 |         // 将顶点信息存入 vertices_
73 |         vertices_[id] = vertex_info;
74 | 
75 |         // 同时为该顶点在 adj_ 中初始化一个空的邻接表（后续 InsertEdge 会往里加边）
76 |         if (adj_.find(id) == adj_.end()) {
77 |             adj_[id] = std::unordered_map<std::string, EdgeNode>();
78 |         }
79 |     }
80 | 
81 |     void LGraph::DeleteVertex(const std::string &place_id) {
82 |         // 删除顶点，并同步删除所有与该顶点相关的边
83 |         //   - 若 place_id 不存在，抛出 GraphException
84 |         auto vertex_it = vertices_.find(place_id);
85 |         if (vertex_it == vertices_.end()) {
86 |             throw GraphException("place_not_found: " + place_id);
87 |         }
88 | 
89 |         // 步骤1：删除该顶点的所有关联边
90 |         // 遍历该顶点的邻接表，对于每条邻边 (place_id → neighbor)：
91 |         //   在 neighbor 的邻接表中也删掉 (neighbor → place_id) 这一条
92 |         auto adj_it = adj_.find(place_id);
93 |         if (adj_it != adj_.end()) {
94 |             for (const auto &neighbor_pair : adj_it->second) {
95 |                 const std::string &neighbor_id = neighbor_pair.first;
96 | 
97 |                 // 在 neighbor 的邻接表中删除 place_id
98 |                 auto neighbor_adj_it = adj_.find(neighbor_id);
99 |                 if (neighbor_adj_it != adj_.end()) {
100 |                     neighbor_adj_it->second.erase(place_id);
101 |                 }
102 |             }
103 |             // 清空该顶点的邻接表
104 |             adj_.erase(adj_it);
105 |         }
106 | 
107 |         // 步骤2：删除顶点本身
108 |         vertices_.erase(vertex_it);
109 |     }
