111 |     void LGraph::UpdateVertex(const std::string &place_id,
112 |                               const std::string &field, const std::string &value) {
113 |         // 按字段名更新顶点信息
114 |         //   支持的字段：display_name, category, stay_time, open_time, close_time
115 |         //   - stay_time 需要将 value 转为 int
116 |         //   - place_id 不存在 → GraphException
117 |         //   - field 不支持 → GraphException
118 |         auto vertex_it = vertices_.find(place_id);
