120 |             throw GraphException("place_not_found: " + place_id);
121 |         }
122 | 
123 |         LocationInfo &info = vertex_it->second;
124 | 
125 |         // 根据字段名更新对应属性
126 |         if (field == "display_name") {
127 |             info.display_name = value;
128 |         } else if (field == "category") {
129 |             info.category = value;
130 |         } else if (field == "stay_time") {
131 |             // stay_time 是 int 类型，需要转换
132 |             info.stay_time = std::stoi(value);
133 |         } else if (field == "open_time") {
134 |             info.open_time = value;
135 |         } else if (field == "close_time") {
136 |             info.close_time = value;
137 |         } else {
138 |             throw GraphException("invalid_field: " + field);
139 |         }
140 |     }
