153 |     void LGraph::InsertEdge(const std::string &from_id, const std::string &to_id,
154 |                             int distance, int walk_time, const std::string &status) {
155 |         // 插入边
156 |         //   - 两端顶点必须都存在，否则抛异常
157 |         //   - 边已存在则抛 GraphException
158 |         //   - 无向图中注意反向关联
159 |         if (!exist_vertex(from_id)) {
160 |             throw GraphException("place_not_found: " + from_id);
161 |         }
162 |         if (!exist_vertex(to_id)) {
163 |             throw GraphException("place_not_found: " + to_id);
164 |         }
165 |         if (exist_edge(from_id, to_id)) {
166 |             throw GraphException("road_already_exists: " + from_id + " -> " + to_id);
167 |         }
168 | 
169 |         // 创建边对象
170 |         EdgeNode edge(from_id, to_id, distance, walk_time, status);
171 | 
172 |         // 在邻接表中插入正向边：from_id → to_id
173 |         adj_[from_id][to_id] = edge;
174 | 
175 |         if (!directed_) {
176 |             // 无向图：同时插入反向边 to_id → from_id
177 |             // 注意反向边的 from_id/to_id 也需要交换
178 |             EdgeNode reverse_edge(to_id, from_id, distance, walk_time, status);
179 |             adj_[to_id][from_id] = reverse_edge;
180 |         }
181 |     }
