183 |     void LGraph::DeleteEdge(const std::string &from_id, const std::string &to_id) {
184 |         // 删除边
185 |         //   - 边不存在 → GraphException
186 |         //   - 无向图中反向边同步删除
187 |         if (!exist_edge(from_id, to_id)) {
188 |             throw GraphException("road_not_found: " + from_id + " -> " + to_id);
189 |         }
190 | 
191 |         // 删除正向边
192 |         adj_[from_id].erase(to_id);
193 | 
194 |         if (!directed_) {
195 |             // 无向图：同时删除反向边
196 |             adj_[to_id].erase(from_id);
197 |         }
198 |     }
