200 |     void LGraph::UpdateEdge(const std::string &from_id, const std::string &to_id,
201 |                             const std::string &field, const std::string &value) {
202 |         // 按字段名更新边
203 |         //   支持字段：distance, walk_time, status
204 |         //   - distance / walk_time 需要转为 int
205 |         //   - status 只能是 "open" 或 "closed"
206 |         //   - 无向图中两个方向需同时更新
207 |         if (!exist_edge(from_id, to_id)) {
208 |             throw GraphException("road_not_found: " + from_id + " -> " + to_id);
209 |         }
210 | 
211 |         // 获取边引用
212 |         EdgeNode &edge = adj_[from_id][to_id];
213 | 
214 |         // 根据字段名更新
215 |         if (field == "distance") {
216 |             int new_dist = std::stoi(value);
217 |             edge.distance = new_dist;
218 |             // 无向图：另一方向也要更新
219 |             if (!directed_) {
220 |                 adj_[to_id][from_id].distance = new_dist;
221 |             }
222 |         } else if (field == "walk_time") {
223 |             int new_time = std::stoi(value);
224 |             edge.walk_time = new_time;
225 |             if (!directed_) {
226 |                 adj_[to_id][from_id].walk_time = new_time;
227 |             }
228 |         } else if (field == "status") {
229 |             if (value != "open" && value != "closed") {
230 |                 throw GraphException("invalid_field: status must be 'open' or 'closed'");
231 |             }
232 |             edge.status = value;
233 |             if (!directed_) {
234 |                 adj_[to_id][from_id].status = value;
235 |             }
236 |         } else {
237 |             throw GraphException("invalid_field: " + field);
238 |         }
239 |     }
