241 |     EdgeNode LGraph::GetEdge(const std::string &from_id, const std::string &to_id) const {
242 |         // 返回边的完整信息
243 |         auto from_it = adj_.find(from_id);
244 |         if (from_it == adj_.end()) {
245 |             throw GraphException("road_not_found: " + from_id + " -> " + to_id);
246 |         }
247 |         auto to_it = from_it->second.find(to_id);
248 |         if (to_it == from_it->second.end()) {
249 |             throw GraphException("road_not_found: " + from_id + " -> " + to_id);
250 |         }
251 |         return to_it->second;
252 |     }
