268 |     std::vector<std::string> LGraph::AllPlaceIds() const {
269 |         // 返回当前图中所有存在的地点 id
270 |         // 顺序：按 place_id 字典序排序，便于输出和测试
271 |         std::vector<std::string> ids;
272 |         ids.reserve(vertices_.size());
273 |         for (const auto &kv : vertices_) {
274 |             ids.push_back(kv.first);
275 |         }
276 |         // 排序以保证确定性输出
277 |         std::sort(ids.begin(), ids.end());
278 |         return ids;
279 |     }
