281 |     std::vector<EdgeNode> LGraph::AllEdges(bool only_open) const {
282 |         // 返回当前图中所有边
283 |         //   - 无向图中每条边只出现一次
284 |         //   - only_open = true 时仅返回 status == "open" 的边
285 |         std::vector<EdgeNode> result;
286 | 
287 |         for (const auto &from_pair : adj_) {
288 |             const std::string &from_id = from_pair.first;
289 |             for (const auto &to_pair : from_pair.second) {
290 |                 const std::string &to_id = to_pair.first;
291 | 
292 |                 if (directed_) {
293 |                     // 有向图：每条边都算
294 |                     if (!only_open || to_pair.second.status == "open") {
295 |                         result.push_back(to_pair.second);
296 |                     }
297 |                 } else {
298 |                     // 无向图：只取 from_id < to_id 的边，避免重复
299 |                     if (from_id < to_id) {
300 |                         if (!only_open || to_pair.second.status == "open") {
301 |                             result.push_back(to_pair.second);
302 |                         }
303 |                     }
304 |                 }
305 |             }
306 |         }
307 | 
308 |         return result;
309 |     }
