311 |     std::vector<EdgeNode> LGraph::GetAdjacentEdges(const std::string &place_id) const {
312 |         // 返回某地点的所有邻接边完整信息
313 |         //   place_id 不存在 → GraphException
314 |         auto adj_it = adj_.find(place_id);
315 |         if (adj_it == adj_.end()) {
316 |             throw GraphException("place_not_found: " + place_id);
317 |         }
318 | 
319 |         std::vector<EdgeNode> result;
320 |         result.reserve(adj_it->second.size());
321 |         for (const auto &neighbor_pair : adj_it->second) {
322 |             result.push_back(neighbor_pair.second);
323 |         }
324 | 
325 |         return result;
326 |     }
