    void CommandProcessor::cmdDeletePlace(std::istringstream &args) {
        // DELETE_PLACE <place_id>
        std::string place_id;
        if (!(args >> place_id)) {
            std::cout << "ERROR invalid_arguments" << std::endl;
            return;
        }

        try {
            // DeleteVertex 内部会级联删除所有邻接边
            graph.DeleteVertex(place_id);
            std::cout << "OK" << std::endl;
